const TOOLTIPS={photosynthesis:"6COâ‚‚ + 6Hâ‚‚O â†’ Câ‚†Hâ‚پâ‚‚Oâ‚† + 6Oâ‚‚","cellular respiration":"Câ‚†Hâ‚پâ‚‚Oâ‚† + 6Oâ‚‚ â†’ 6COâ‚‚ + 6Hâ‚‚O + energy (ATP)",combustion:"Hydrocarbon + Oâ‚‚ â†’ COâ‚‚ + Hâ‚‚O + energy (e.g., CHâ‚„ + 2Oâ‚‚ â†’ COâ‚‚ + 2Hâ‚‚O + energy).",biosphere:"All living organisms and their ecosystems.",hydrosphere:"All the water on Earth- oceans, lakes, rivers, groundwater, and water vapor in the atmosphere.",lithosphere:"The crust and upper mantle (e.g., Rocks, minerals, landforms).",anthropogenic:"Caused by human action or inaction",leaching:"water dissolves and carries double materials from soil's top layer, and mining, the phosphorus then reaches the soil","haber-bosch process":"An industrial process that synthesizes ammonia from nitrogen and hydrogen","higher plants":"Plants that have vein tissue and can be planted like trees and ferns",guano:"organic solid waste from seabirds"};document.activateTooltips=()=>{var terms=document.querySelectorAll(".tooltip");terms.forEach((term)=>{const key=term.textContent.toLowerCase().trim();const definition=TOOLTIPS[key];if(definition){term.setAttribute("data-tooltip",definition)}else{term.setAttribute("data-tooltip","An error was encountered when loading the definition. Please report this bug to dev@jayagra.com.")}})};